5888 // Canonicalize checking for a power-of-2-or-zero value:
5889 static Instruction *foldICmpPow2Test(ICmpInst &I,
5890                                      InstCombiner::BuilderTy &Builder) {
5891   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
5892   const CmpInst::Predicate Pred = I.getPredicate();
5893   Value *A = nullptr;
5894   bool CheckIs;
5895   if (I.isEquality()) {
5896     // (A & (A-1)) == 0 --> ctpop(A) < 2 (two commuted variants)
5897     // ((A-1) & A) != 0 --> ctpop(A) > 1 (two commuted variants)
5898     if (!match(Op0, m_OneUse(m_c_And(m_Add(m_Value(A), m_AllOnes()),
5899                                      m_Deferred(A)))) ||
5900         !match(Op1, m_ZeroInt()))
5901       A = nullptr;
5902 
5903     // (A & -A) == A --> ctpop(A) < 2 (four commuted variants)
5904     // (-A & A) != A --> ctpop(A) > 1 (four commuted variants)
5905     if (match(Op0, m_OneUse(m_c_And(m_Neg(m_Specific(Op1)), m_Specific(Op1)))))
5906       A = Op1;
5907     else if (match(Op1,
5908                    m_OneUse(m_c_And(m_Neg(m_Specific(Op0)), m_Specific(Op0)))))
5909       A = Op0;
5910 
5911     CheckIs = Pred == ICmpInst::ICMP_EQ;
5912   } else if (ICmpInst::isUnsigned(Pred)) {
5913     // (A ^ (A-1)) u>= A --> ctpop(A) < 2 (two commuted variants)
5914     // ((A-1) ^ A) u< A --> ctpop(A) > 1 (two commuted variants)
5915 
5916     if ((Pred == ICmpInst::ICMP_UGE || Pred == ICmpInst::ICMP_ULT) &&
5917         match(Op0, m_OneUse(m_c_Xor(m_Add(m_Specific(Op1), m_AllOnes()),
5918                                     m_Specific(Op1))))) {
5919       A = Op1;
5920       CheckIs = Pred == ICmpInst::ICMP_UGE;
5921     } else if ((Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_ULE) &&
5922                match(Op1, m_OneUse(m_c_Xor(m_Add(m_Specific(Op0), m_AllOnes()),
5923                                            m_Specific(Op0))))) {
5924       A = Op0;
5925       CheckIs = Pred == ICmpInst::ICMP_ULE;
